total_allocated_amount = 0.0
total_billed = 0.0
for milestone in doc.get('custom_project_milestones', []):
    if not milestone.planned_date:
        frappe.throw(f"Planned Date is mandatory for milestone '{milestone.milestone_name}'")
    total_allocated_amount += frappe.utils.flt(milestone.amount)
    if milestone.status == 'Invoiced':
        total_billed += frappe.utils.flt(milestone.amount)

contract_value = frappe.utils.flt(doc.custom_total_contract_value)
coverage_pct = frappe.utils.flt((total_allocated_amount / contract_value) * 100, 2) if contract_value > 0 else 0.0

if contract_value > 0 and total_allocated_amount > contract_value:
    frappe.throw('Milestones total (' + str(total_allocated_amount) + ') cannot exceed Contract Value (' + str(contract_value) + ')')

if coverage_pct < 100 and len(doc.get('custom_project_milestones', [])) > 0:
    frappe.msgprint('Warning: Milestones cover ' + str(coverage_pct) + '% of contract.', indicator='orange', alert=1)

doc.custom_total_completed__ = coverage_pct
doc.total_billed_amount = total_billed

for milestone in doc.get("custom_project_milestones", []):
    if milestone.status == "Approved" and not milestone.sales_order:
        so = frappe.new_doc("Sales Order")
        so.customer = doc.customer
        so.company = doc.company
        so.project = doc.name
        so.custom_is_proforma_invoice = 1
        so.delivery_date = milestone.planned_date or frappe.utils.today()

        items = []
        if milestone.milestone_items_json:
            items = frappe.utils.parse_json(milestone.milestone_items_json)

        if items:
            for item in items:
                if not item.get('item_code'): continue
                item_doc = frappe.get_doc("Item", item['item_code'])
                warehouse = None
                if item_doc.is_stock_item:
                    warehouse = frappe.db.get_value("Item Default",
                        {"parent": item['item_code'], "company": doc.company},
                        "default_warehouse") or "Stores - SD"
                    actual_qty = frappe.db.get_value("Bin",
                        {"item_code": item['item_code'], "warehouse": warehouse},
                        "actual_qty") or 0
                    if actual_qty <= 0:
                        frappe.msgprint(
                            f"Item {item['item_code']} is out of stock. Skipping.",
                            indicator="red", title="Out of Stock"
                        )
                        continue
                qty = frappe.utils.flt(item['qty']) or 1
                milestone_amount = frappe.utils.flt(item['milestone_amount'])
                rate = milestone_amount / qty if qty else milestone_amount
                so.append("items", {
                    "item_code": item['item_code'],
                    "item_name": item['item_name'],
                    "qty": qty,
                    "rate": rate,
                    "delivery_date": milestone.planned_date or frappe.utils.today(),
                    "warehouse": warehouse
                })
        else:
            if doc.custom_quotation:
                quotation = frappe.get_doc("Quotation", doc.custom_quotation)
                for item in quotation.items:
                    qty = frappe.utils.flt(item.qty) or 1
                    rate = frappe.utils.flt(item.amount) / qty if qty else frappe.utils.flt(item.amount)
                    so.append("items", {
                        "item_code": item.item_code,
                        "item_name": item.item_name,
                        "qty": qty,
                        "rate": rate,
                        "delivery_date": milestone.planned_date or frappe.utils.today()
                    })
            else:
                so.append("items", {
                    "item_code": "CONSULTING_SVC_MILESTONE",
                    "item_name": milestone.milestone_name,
                    "qty": 1,
                    "rate": milestone.amount,
                    "delivery_date": milestone.planned_date or frappe.utils.today()
                })

        so.insert(ignore_permissions=True)
        so.submit()
        frappe.db.set_value("Project Milestone", milestone.name, "sales_order", so.name)

    if milestone.status == "Invoiced" and not milestone.invoice_created and milestone.sales_order:
        planned_date = frappe.db.get_value("Project Milestone", milestone.name, "planned_date") or frappe.utils.today()
        si = frappe.new_doc("Sales Invoice")
        si.customer = doc.customer
        si.company = doc.company
        si.project = doc.name
        si.posting_date = planned_date
        si.set_posting_time = 1

        items = []
        if milestone.milestone_items_json:
            items = frappe.utils.parse_json(milestone.milestone_items_json)

        if items:
            for item in items:
                if not item.get('item_code'): continue
                qty = frappe.utils.flt(item['qty']) or 1
                milestone_amount = frappe.utils.flt(item['milestone_amount'])
                rate = milestone_amount / qty if qty else milestone_amount
                si.append("items", {
                    "item_code": item['item_code'],
                    "item_name": item['item_name'],
                    "qty": qty,
                    "rate": rate
                })
        else:
            if doc.custom_quotation:
                quotation = frappe.get_doc("Quotation", doc.custom_quotation)
                for item in quotation.items:
                    qty = frappe.utils.flt(item.qty) or 1
                    rate = frappe.utils.flt(item.amount) / qty if qty else frappe.utils.flt(item.amount)
                    si.append("items", {
                        "item_code": item.item_code,
                        "item_name": item.item_name,
                        "qty": qty,
                        "rate": rate
                    })
            else:
                si.append("items", {
                    "item_code": "CONSULTING_SVC_MILESTONE",
                    "item_name": milestone.milestone_name,
                    "qty": 1,
                    "rate": milestone.amount
                })

        si.insert(ignore_permissions=True)
        si.submit()
        frappe.db.set_value("Project Milestone", milestone.name, {
            "sales_invoice": si.name,
            "invoice_created": 1
        })
